var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"시공간 수정의 후유증은 꽤나 다양해, 친구.","JPN":"時空間修正の後遺症は、かなり様々だ。","ENG":"Side effects of spacetime recalibration are quite diverse, my friend.","TWN":"修正時空會引起多種後遺症，朋友。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"특히나 자네처럼 많이 겪은 경우에는...... 무슨 일이 일어날지 장담할 수 없어.","JPN":"特に君のように、色んなことがあった場合……何が起きるかわからない。","ENG":"And for someone who has done it multiple times like yourself, there's no telling what might happen.","TWN":"特別是像你這種經歷了很多次的情況……我無法保證會發生什麼。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 자네의 길잡이로서, 이것 하나는 얘기해 줄 수 있겠군.","JPN":"だが、君のガイドとして、これだけは言える。","ENG":"But as your guide, I can tell you this.","TWN":"但作為你的領路人，我可以告訴你一點。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"꿈에서 다른 사람과 눈을 마주치게 되더라도 너무 놀라진 마. 그건 실제가 아니고, 그들의 추억을 잠시 관측하는 것 뿐이니까.","JPN":"夢の中で他の人と目が合っても、あまり驚くな。それは現実ではなく、彼らの思い出を少し観察するにすぎない。","ENG":"Don't be too surprised if you get to make eye contact with someone else. It's not real. You're observing their memories for a short period of time.","TWN":"在夢裡，即使與他人對上視線也不要太驚訝。因為那並不是現實，你只是在暫時觀看他們的回憶而已。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 사람들의 행복했던 시절을 함께 돌아보는 것도...... 자네가 앞으로 걸을 길에 작은 위안 정도는 되겠지.","JPN":"だが、誰かの幸せだった時期を一緒に振り返るのも……これから君が歩むべき道の、小さな癒しにはなるだろう。","ENG":"But looking back at people's memories of their happy past could provide some comfort for your mind while walking the path you're on.","TWN":"不過，與他人一同觀看幸福的回憶……或許能在你前行的道路上，成為小小的慰藉。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DAUGHTER_EDDIE_NULL_CHILD","text":{"KOREA":"아빠~ 이것 봐~","JPN":"お父さ～ん、これ見て。","ENG":"Daddy, look!","TWN":"爸爸~看這裡~"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"DAUGHTER_EDDIE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DAUGHTER_EDDIE_NULL_CHILD","text":{"KOREA":"길에 물웅덩이가 잔뜩 생겼어. 걸을 때마다 찰박찰박해.","JPN":"道に水たまりがいっぱいだよ。歩くと、ちゃぷちゃぷする。","ENG":"There are puddles on the road! Lots of them! They go splash when I step on them.","TWN":"路上有好多水坑呢。踩在上面會發出啪嗒啪嗒的聲音。"},"stage":{"bg":"BACKSTREET","slots":{"L":{"char_id":"DAUGHTER_EDDIE_NULL_CHILD","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_CHILD","text":{"KOREA":"얘야, 우산 아래 잘 있어야지. 옷이 젖으면 엄마한테 또 야단 맞아요.","JPN":"こら、傘をしっかり差さないとダメだろ。服が濡れたら、またお母さんに怒られちゃうぞ。","ENG":"Honey, you should stay under the umbrella. Mommy will be angry if she sees you all wet again.","TWN":"孩子，好好待在雨傘下面呀。衣服濕了又要被媽媽罵了。"},"stage":{"bg":"BACKSTREET","slots":{"L":{"char_id":"DAUGHTER_EDDIE_NULL_CHILD","face":"UNIT_LAUGH"},"C":{"char_id":"EDDIE_RSEVEN_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DAUGHTER_EDDIE_NULL_CHILD","text":{"KOREA":"나? 아니면 아빠?","JPN":"私？　それともお父さん？","ENG":"Angry at who? Me or you?","TWN":"我？或者是爸爸？"},"stage":{"bg":"BACKSTREET","slots":{"L":{"char_id":"DAUGHTER_EDDIE_NULL_CHILD","face":"UNIT_SURPRISE"},"C":{"char_id":"EDDIE_RSEVEN_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_CHILD","text":{"KOREA":"글쎄, 둘 다 야단 맞지 않을까?","JPN":"さあ、二人ともかな？","ENG":"Well, I'd say both.","TWN":"誰知道啊，會不會被爸爸媽媽一起罵呢？"},"stage":{"bg":"BACKSTREET","slots":{"L":{"char_id":"DAUGHTER_EDDIE_NULL_CHILD","face":"UNIT_SURPRISE"},"C":{"char_id":"EDDIE_RSEVEN_NULL_CHILD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DAUGHTER_EDDIE_NULL_CHILD","text":{"KOREA":"엄마 무셔~","JPN":"お母さん、こわ～い。","ENG":"Mommy's scary!","TWN":"媽媽好可怕~"},"stage":{"bg":"BACKSTREET","slots":{"L":{"char_id":"DAUGHTER_EDDIE_NULL_CHILD","face":"UNIT_LAUGH"},"C":{"char_id":"EDDIE_RSEVEN_NULL_CHILD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_CHILD","text":{"KOREA":"하하, 그 말 들으면 엄마가 많이 섭섭해 하시겠네.","JPN":"はは、お母さんが聞いたら悲しむな。","ENG":"Hah hah, I'm glad that your mom isn't around to hear that.","TWN":"哈哈，媽媽聽到這話會難過的。"},"stage":{"bg":"BACKSTREET","slots":{"L":{"char_id":"DAUGHTER_EDDIE_NULL_CHILD","face":"UNIT_LAUGH"},"C":{"char_id":"EDDIE_RSEVEN_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DAUGHTER_EDDIE_NULL_CHILD","text":{"KOREA":"그치만 엄마는 매일 나랑 같이 있는걸.","JPN":"でも、お母さんはいつも一緒だもん。","ENG":"But Mommy's with me all day.","TWN":"但媽媽每天都陪在你身邊。"},"stage":{"bg":"BACKSTREET","slots":{"L":{"char_id":"DAUGHTER_EDDIE_NULL_CHILD","face":"UNIT_IDLE"},"C":{"char_id":"EDDIE_RSEVEN_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DAUGHTER_EDDIE_NULL_CHILD","text":{"KOREA":"아빠는 일 때문에 바빠서 집에 오래 못 있잖아.","JPN":"お父さんは忙しくて、家にいないでしょ。","ENG":"You're too busy to spend time with me during the day.","TWN":"爸爸因為工作不能一直待在家裡。"},"stage":{"bg":"BACKSTREET","slots":{"L":{"char_id":"DAUGHTER_EDDIE_NULL_CHILD","face":"UNIT_SERIOUS"},"C":{"char_id":"EDDIE_RSEVEN_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DAUGHTER_EDDIE_NULL_CHILD","text":{"KOREA":"그러니까 난 아빠가 집에 있는 날엔 아빠랑 더 많이 놀고 싶어.","JPN":"だから、お父さんが家にいる時は、お父さんともっといっぱい遊ぶの。","ENG":"So I want to play with you more when you're at home.","TWN":"所以，爸爸在家時，我就想多跟爸爸一起玩。"},"stage":{"bg":"BACKSTREET","slots":{"L":{"char_id":"DAUGHTER_EDDIE_NULL_CHILD","face":"UNIT_IDLE"},"C":{"char_id":"EDDIE_RSEVEN_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_CHILD","text":{"KOREA":"......우리 딸 고맙네. 아빠 생각도 해 주고.","JPN":"……ありがとう。お父さんに優しくしてくれて。","ENG":"Oh, thanks, sweetie. It's very sweet of you to think that.","TWN":"……謝謝乖女兒。還想著爸爸。"},"stage":{"bg":"BACKSTREET","slots":{"L":{"char_id":"DAUGHTER_EDDIE_NULL_CHILD","face":"UNIT_IDLE"},"C":{"char_id":"EDDIE_RSEVEN_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DAUGHTER_EDDIE_NULL_CHILD","text":{"KOREA":"당연하지~ 엄마는 놀이공원 같이 안 가 주잖아~","JPN":"当然だよ～だってお母さんは、遊園地に連れて行ってくれないから～","ENG":"Sure. Mommy won't go to out to play with me.","TWN":"當然了~媽媽都不帶我去遊樂園嘛~"},"stage":{"bg":"BACKSTREET","slots":{"L":{"char_id":"DAUGHTER_EDDIE_NULL_CHILD","face":"UNIT_PRIDE"},"C":{"char_id":"EDDIE_RSEVEN_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_CHILD","text":{"KOREA":"하하하, 욘석. 너도 다 꿍꿍이가 있었구나.","JPN":"ははは、そういうことだったのか。","ENG":"Hah hah! Now I get why you wanted me to come out with you.","TWN":"哈哈哈，你這小東西。心裡也有自己的小算盤嘛。"},"stage":{"bg":"BACKSTREET","slots":{"L":{"char_id":"DAUGHTER_EDDIE_NULL_CHILD","face":"UNIT_PRIDE"},"C":{"char_id":"EDDIE_RSEVEN_NULL_CHILD","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};